module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;

    always @(A or B) begin
        dividend <= A;
        divisor <= B;
    end

    always @(dividend or divisor) begin
        if (dividend[15:8] >= divisor) begin
            remainder <= dividend[15:8] - divisor;
            quotient[15] <= 1'b1;
        end
        else begin
            remainder <= dividend[15:8];
            quotient[15] <= 1'b0;
        end

        if (dividend[14:7] >= divisor) begin
            remainder[14:7] <= dividend[14:7] - divisor;
            quotient[14] <= 1'b1;
        end
        else begin
            remainder[14:7] <= dividend[14:7];
            quotient[14] <= 1'b0;
        end

        if (dividend[13:6] >= divisor) begin
            remainder[13:6] <= dividend[13:6] - divisor;
            quotient[13] <= 1'b1;
        end
        else begin
            remainder[13:6] <= dividend[13:6];
            quotient[13] <= 1'b0;
        end

        if (dividend[12:5] >= divisor) begin
            remainder[12:5] <= dividend[12:5] - divisor;
            quotient[12] <= 1'b1;
        end
        else begin
            remainder[12:5] <= dividend[12:5];
            quotient[12] <= 1'b0;
        end

        if (dividend[11:4] >= divisor) begin
            remainder[11:4] <= dividend[11:4] - divisor;
            quotient[11] <= 1'b1;
        end
        else begin
            remainder[11:4] <= dividend[11:4];
            quotient[11] <= 1'b0;
        end

        if (dividend[10:3] >= divisor) begin
            remainder[10:3] <= dividend[10:3] - divisor;
            quotient[10] <= 1'b1;
        end
        else begin
            remainder[10:3] <= dividend[10:3];
            quotient[10] <= 1'b0;
        end

        if (dividend[9:2] >= divisor) begin
            remainder[9:2] <= dividend[9:2] - divisor;
            quotient[9] <= 1'b1;
        end
        else begin
            remainder[9:2] <= dividend[9:2];
            quotient[9] <= 1'b0;
        end

        if (dividend[8:1] >= divisor) begin
            remainder[8:1] <= dividend[8:1] - divisor;
            quotient[8] <= 1'b1;
        end
        else begin
            remainder[8:1] <= dividend[8:1];
            quotient[8] <= 1'b0;
        end

        if (dividend[7:0] >= divisor) begin
            remainder[7:0] <= dividend[7:0] - divisor;
            quotient[7] <= 1'b1;
        end
        else begin
            remainder[7:0] <= dividend[7:0];
            quotient[7] <= 1'b0;
        end

        result <= quotient;
        odd <= remainder;
    end
endmodule
